import pytest
import requests

def test_missing_required_fields_returns_422(clinician_headers, base_url):
    payload = {
        "resourceType": "AllergyIntolerance",
        "clinicalStatus": {"coding": [{"system": "http://terminology.hl7.org/CodeSystem/allergyintolerance-clinical", "code": "active"}]}
    }
    r = requests.post(f"{base_url}/AllergyIntolerance", json=payload, headers=clinician_headers)
    assert r.status_code == 422, f"Expected 422, got {r.status_code}: {r.text}"
    body = r.json()
    assert body.get("resourceType") == "OperationOutcome"
    issues = body.get("issue", [])
    assert len(issues) >= 1
    severities = {i.get("severity") for i in issues}
    assert severities & {"error", "fatal"}, f"No error-level issue found: {issues}"
